import React, { useState, useEffect } from 'react';
import { Button, Loading, ErrorMessage } from '../components/atoms';
import { getProducts, createProduct, updateProduct, deleteProduct } from '../services/productService';
import { getUsers, createUser, updateUser, deleteUser } from '../services/userService';
import { getAllOrders, updateOrderStatus } from '../services/orderService';
import './AdminDashboard.css';

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState('productos');
  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Modals state
  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUser, setEditingUser] = useState(null);

  // Product Form State
  const [prodName, setProdName] = useState('');
  const [prodPrice, setProdPrice] = useState('');
  const [prodStock, setProdStock] = useState('');
  const [prodCategory, setProdCategory] = useState('Cafés');
  const [prodDescription, setProdDescription] = useState('');

  // User Form State
  const [userName, setUserName] = useState('');
  const [userEmail, setUserEmail] = useState('');
  const [userPassword, setUserPassword] = useState('');
  const [userRole, setUserRole] = useState('Cliente');

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setError('');
    setLoading(true);
    try {
      if (activeTab === 'productos') {
        const data = await getProducts();
        setProducts(data.data || data || []);
      } else if (activeTab === 'usuarios') {
        const data = await getUsers();
        setUsers(data || []);
      } else if (activeTab === 'ordenes' || activeTab === 'finanzas') {
        const data = await getAllOrders();
        setOrders(data.orders || data || []);
      }
    } catch (err) {
      console.error("Error loading admin data:", err);
      setError('No se pudo cargar la información desde el servidor.');
    } finally {
      setLoading(false);
    }
  };

  // PRODUCT CRUD HANDLERS
  const openNewProductModal = () => {
    setEditingProduct(null);
    setProdName('');
    setProdPrice('');
    setProdStock('');
    setProdCategory('Cafés');
    setProdDescription('');
    setShowProductModal(true);
  };

  const openEditProductModal = (product) => {
    setEditingProduct(product);
    setProdName(product.name);
    setProdPrice(product.price);
    setProdStock(product.stock);
    setProdCategory(product.category || 'Cafés');
    setProdDescription(product.description || '');
    setShowProductModal(true);
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    setError('');
    const productPayload = {
      name: prodName,
      price: Number(prodPrice),
      stock: Number(prodStock),
      category: prodCategory,
      description: prodDescription
    };

    try {
      if (editingProduct) {
        await updateProduct(editingProduct._id, productPayload);
      } else {
        await createProduct(productPayload);
      }
      setShowProductModal(false);
      loadData();
    } catch (err) {
      console.error("Error saving product:", err);
      setError('No se pudo guardar el producto. Verifica los datos.');
    }
  };

  const handleProductDelete = async (id) => {
    if (window.confirm('¿Estás seguro de que deseas eliminar este producto?')) {
      try {
        await deleteProduct(id);
        loadData();
      } catch (err) {
        console.error("Error deleting product:", err);
        setError('Error al intentar eliminar el producto.');
      }
    }
  };

  // USER CRUD HANDLERS
  const openNewUserModal = () => {
    setEditingUser(null);
    setUserName('');
    setUserEmail('');
    setUserPassword('');
    setUserRole('Cliente');
    setShowUserModal(true);
  };

  const openEditUserModal = (user) => {
    setEditingUser(user);
    setUserName(user.nombre);
    setUserEmail(user.email);
    setUserPassword(''); // Leave blank unless updating
    setUserRole(user.role || 'Cliente');
    setShowUserModal(true);
  };

  const handleUserSubmit = async (e) => {
    e.preventDefault();
    setError('');
    const userPayload = {
      nombre: userName,
      email: userEmail,
      rol: userRole,
    };
    if (userPassword) {
      userPayload.password = userPassword;
    } else if (!editingUser) {
      setError('La contraseña es requerida para nuevos usuarios.');
      return;
    }

    try {
      if (editingUser) {
        await updateUser(editingUser._id, userPayload);
      } else {
        await createUser(userPayload);
      }
      setShowUserModal(false);
      loadData();
    } catch (err) {
      console.error("Error saving user:", err);
      setError('Error al guardar el usuario. Verifica si el email ya existe.');
    }
  };

  const handleUserDelete = async (id) => {
    if (window.confirm('¿Estás seguro de que deseas eliminar este usuario?')) {
      try {
        await deleteUser(id);
        loadData();
      } catch (err) {
        console.error("Error deleting user:", err);
        setError('Error al intentar eliminar al usuario.');
      }
    }
  };

  // ORDER STATUS HANDLERS
  const handleOrderStatusChange = async (orderId, newStatus) => {
    try {
      await updateOrderStatus(orderId, newStatus);
      // Update locally
      setOrders(orders.map(o => o._id === orderId ? { ...o, status: newStatus, estado: newStatus } : o));
    } catch (err) {
      console.error("Error changing order status:", err);
      setError('No se pudo actualizar el estado de la orden.');
    }
  };

  // FINANCIAL CALCULATIONS
  const getTodaySales = () => {
    const todayStr = new Date().toDateString();
    return orders
      .filter(o => o.status === 'Completada' && new Date(o.date).toDateString() === todayStr)
      .reduce((sum, o) => sum + (o.total || 0), 0);
  };

  const getMonthSales = () => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    return orders
      .filter(o => {
        if (o.status !== 'Completada') return false;
        const d = new Date(o.date);
        return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
      })
      .reduce((sum, o) => sum + (o.total || 0), 0);
  };

  const getHistoricalSales = () => {
    return orders
      .filter(o => o.status === 'Completada')
      .reduce((sum, o) => sum + (o.total || 0), 0);
  };

  const formatMoney = (value) => {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: 'MXN'
    }).format(value);
  };

  return (
    <div className="admin-dashboard">
      <div className="admin-sidebar">
        <h2>Panel Admin</h2>
        <ul className="admin-nav">
          <li className={activeTab === 'productos' ? 'active' : ''} onClick={() => setActiveTab('productos')}>📁 Productos</li>
          <li className={activeTab === 'ordenes' ? 'active' : ''} onClick={() => setActiveTab('ordenes')}>📋 Órdenes</li>
          <li className={activeTab === 'usuarios' ? 'active' : ''} onClick={() => setActiveTab('usuarios')}>👥 Usuarios</li>
          <li className={activeTab === 'finanzas' ? 'active' : ''} onClick={() => setActiveTab('finanzas')}>💰 Finanzas</li>
        </ul>
      </div>

      <div className="admin-content">
        {error && <ErrorMessage>{error}</ErrorMessage>}

        {loading ? (
          <div className="loading-container">
            <Loading message="Cargando información..." />
          </div>
        ) : (
          <>
            {activeTab === 'productos' && (
              <div className="admin-section">
                <div className="section-header">
                  <h2>Gestión de Productos</h2>
                  <Button variant="primary" onClick={openNewProductModal}>+ Crear Nuevo Producto</Button>
                </div>
                <div className="table-container">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>Nombre</th>
                        <th>Categoría</th>
                        <th>Precio</th>
                        <th>Stock</th>
                        <th>Descripción</th>
                        <th>Acciones</th>
                      </tr>
                    </thead>
                    <tbody>
                      {products.map(product => (
                        <tr key={product._id}>
                          <td><strong>{product.name}</strong></td>
                          <td>{product.category || 'Sin categoría'}</td>
                          <td>{formatMoney(product.price)}</td>
                          <td>{product.stock} uds</td>
                          <td>{product.description || '-'}</td>
                          <td>
                            <div className="action-buttons">
                              <button className="btn-icon btn-edit" onClick={() => openEditProductModal(product)} title="Editar">✏️</button>
                              <button className="btn-icon btn-delete" onClick={() => handleProductDelete(product._id)} title="Eliminar">🗑️</button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'ordenes' && (
              <div className="admin-section">
                <div className="section-header">
                  <h2>Gestión de Órdenes</h2>
                </div>
                <div className="table-container">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>ID Orden</th>
                        <th>Cliente</th>
                        <th>Fecha</th>
                        <th>Total</th>
                        <th>Pago</th>
                        <th>Estado</th>
                      </tr>
                    </thead>
                    <tbody>
                      {orders.map(order => (
                        <tr key={order._id}>
                          <td>#{order._id.substring(order._id.length - 6)}</td>
                          <td>{order.usuario?.nombre || 'Invitado'} <br/><span style={{fontSize:'0.75rem', color:'#64748b'}}>{order.usuario?.email || ''}</span></td>
                          <td>{new Date(order.date).toLocaleString('es-MX')}</td>
                          <td><strong>{formatMoney(order.total)}</strong></td>
                          <td>{order.metodoPago || 'Efectivo'}</td>
                          <td>
                            <select 
                              className="status-select"
                              value={order.status}
                              onChange={(e) => handleOrderStatusChange(order._id, e.target.value)}
                            >
                              <option value="Pendiente">Pendiente</option>
                              <option value="Completada">Completada</option>
                              <option value="Cancelada">Cancelada</option>
                            </select>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'usuarios' && (
              <div className="admin-section">
                <div className="section-header">
                  <h2>Gestión de Usuarios</h2>
                  <Button variant="primary" onClick={openNewUserModal}>+ Añadir Usuario</Button>
                </div>
                <div className="table-container">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>Nombre</th>
                        <th>Email</th>
                        <th>Rol</th>
                        <th>Acciones</th>
                      </tr>
                    </thead>
                    <tbody>
                      {users.map(user => (
                        <tr key={user._id}>
                          <td><strong>{user.nombre}</strong></td>
                          <td>{user.email}</td>
                          <td>
                            <span style={{
                              padding: '0.25rem 0.5rem', 
                              borderRadius: '6px', 
                              fontSize: '0.8rem',
                              fontWeight: '600',
                              backgroundColor: user.rol === 'Administrador' ? '#fee2e2' : user.rol === 'Chef' ? '#fef9c3' : '#e0f2fe',
                              color: user.rol === 'Administrador' ? '#991b1b' : user.rol === 'Chef' ? '#854d0e' : '#0369a1'
                            }}>
                              {user.rol}
                            </span>
                          </td>
                          <td>
                            <div className="action-buttons">
                              <button className="btn-icon btn-edit" onClick={() => openEditUserModal(user)} title="Editar">✏️</button>
                              <button className="btn-icon btn-delete" onClick={() => handleUserDelete(user._id)} title="Eliminar">🗑️</button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'finanzas' && (
              <div className="admin-section">
                <div className="section-header">
                  <h2>Ganancias y Finanzas</h2>
                </div>

                <div className="stats-grid">
                  <div className="stat-card">
                    <h3>Ventas Hoy</h3>
                    <p>{formatMoney(getTodaySales())}</p>
                  </div>
                  <div className="stat-card blue">
                    <h3>Ventas Mes</h3>
                    <p>{formatMoney(getMonthSales())}</p>
                  </div>
                  <div className="stat-card orange">
                    <h3>Ventas Históricas</h3>
                    <p>{formatMoney(getHistoricalSales())}</p>
                  </div>
                  <div className="stat-card">
                    <h3>Órdenes Totales</h3>
                    <p>{orders.length}</p>
                  </div>
                </div>

                <div className="section-header" style={{ marginTop: '2rem', borderBottom: 'none' }}>
                  <h3>Detalle de Ventas Completadas</h3>
                </div>
                <div className="table-container">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>ID Orden</th>
                        <th>Cliente</th>
                        <th>Fecha</th>
                        <th>Método Pago</th>
                        <th>Monto</th>
                      </tr>
                    </thead>
                    <tbody>
                      {orders
                        .filter(o => o.status === 'Completada')
                        .map(order => (
                          <tr key={order._id}>
                            <td>#{order._id.substring(order._id.length - 6)}</td>
                            <td>{order.usuario?.nombre || 'Invitado'}</td>
                            <td>{new Date(order.date).toLocaleString('es-MX')}</td>
                            <td>{order.metodoPago}</td>
                            <td><strong>{formatMoney(order.total)}</strong></td>
                          </tr>
                        ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* PRODUCT MODAL */}
      {showProductModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h3>{editingProduct ? 'Editar Producto' : 'Crear Nuevo Producto'}</h3>
            <form onSubmit={handleProductSubmit}>
              <div className="form-row">
                <label>Nombre del Producto *</label>
                <input 
                  type="text" 
                  value={prodName} 
                  onChange={(e) => setProdName(e.target.value)} 
                  required 
                  placeholder="Ej. Café Espresso"
                />
              </div>
              <div className="form-row">
                <label>Precio *</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={prodPrice} 
                  onChange={(e) => setProdPrice(e.target.value)} 
                  required 
                  placeholder="Ej. 45.00"
                />
              </div>
              <div className="form-row">
                <label>Stock *</label>
                <input 
                  type="number" 
                  value={prodStock} 
                  onChange={(e) => setProdStock(e.target.value)} 
                  required 
                  placeholder="Ej. 100"
                />
              </div>
              <div className="form-row">
                <label>Categoría *</label>
                <select 
                  value={prodCategory} 
                  onChange={(e) => setProdCategory(e.target.value)}
                >
                  <option value="Cafés">Cafés</option>
                  <option value="Panadería">Panadería</option>
                  <option value="Bebidas">Bebidas</option>
                  <option value="Postres">Postres</option>
                  <option value="Otros">Otros</option>
                </select>
              </div>
              <div className="form-row">
                <label>Descripción</label>
                <textarea 
                  value={prodDescription} 
                  onChange={(e) => setProdDescription(e.target.value)} 
                  placeholder="Ingresa la descripción del producto..."
                  rows="3"
                />
              </div>
              <div className="modal-actions">
                <Button type="button" variant="secondary" onClick={() => setShowProductModal(false)}>Cancelar</Button>
                <Button type="submit" variant="primary">Guardar</Button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* USER MODAL */}
      {showUserModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h3>{editingUser ? 'Editar Usuario' : 'Añadir Nuevo Usuario'}</h3>
            <form onSubmit={handleUserSubmit}>
              <div className="form-row">
                <label>Nombre Completo *</label>
                <input 
                  type="text" 
                  value={userName} 
                  onChange={(e) => setUserName(e.target.value)} 
                  required 
                  placeholder="Ej. Juan Pérez"
                />
              </div>
              <div className="form-row">
                <label>Email *</label>
                <input 
                  type="email" 
                  value={userEmail} 
                  onChange={(e) => setUserEmail(e.target.value)} 
                  required 
                  placeholder="ejemplo@cafesito.com"
                />
              </div>
              <div className="form-row">
                <label>{editingUser ? 'Nueva Contraseña (dejar vacío para mantener actual)' : 'Contraseña *'}</label>
                <input 
                  type="password" 
                  value={userPassword} 
                  onChange={(e) => setUserPassword(e.target.value)} 
                  required={!editingUser}
                  placeholder="Contraseña"
                />
              </div>
              <div className="form-row">
                <label>Rol *</label>
                <select 
                  value={userRole} 
                  onChange={(e) => setUserRole(e.target.value)}
                >
                  <option value="Administrador">Administrador</option>
                  <option value="Cajero">Cajero</option>
                  <option value="Chef">Chef</option>
                  <option value="Cliente">Cliente</option>
                </select>
              </div>
              <div className="modal-actions">
                <Button type="button" variant="secondary" onClick={() => setShowUserModal(false)}>Cancelar</Button>
                <Button type="submit" variant="primary">Guardar</Button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
